class ChartRenderer {
    private static final String BAR_CHART_TYPE = "bar";
    private static final String LINE_CHART_TYPE = "line";

    ChartConfiguration createBarChartConfiguration(String title, List<DataSeries> dataSeries) {
        return ChartConfiguration.builder()
            .withType(BAR_CHART_TYPE)
            .withTitle(title)
            .withDataSeries(dataSeries)
            .build();
    }
}
